examples:
security_group_rules = {
    egress_postgresql = {
      description = "Allow egress to PostgreSQL"
      from_port   = 5432
      to_port     = 5432
      protocol    = "tcp"
      cidr_blocks = module.vpc.private_subnets_cidr_blocks
    }
  }

workspace_api_keys = {
    viewer = {
      key_name        = "viewer"
      key_role        = "VIEWER"
      seconds_to_live = 3600
    }
    editor = {
      key_name        = "editor"
      key_role        = "EDITOR"
      seconds_to_live = 3600
    }
    admin = {
      key_name        = "admin"
      key_role        = "ADMIN"
      seconds_to_live = 3600
    }
  }

workspace_service_account_tokens = {
    viewer = {
      service_account_key = "viewer"
      seconds_to_live     = 3600
    }
    editor = {
      name                = "editor-example"
      service_account_key = "editor"
      seconds_to_live     = 3600
    }
    admin = {
      service_account_key = "admin"
      seconds_to_live     = 3600
    }
  }

workspace_service_accounts = {
    viewer = {
      grafana_role = "VIEWER"
    }
    editor = {
      name         = "editor-example"
      grafana_role = "EDITOR"
    }
    admin = {
      grafana_role = "ADMIN"
    }
  }
